package main

import (
	"fmt"
	"strings"
	"time"
)

// BuildFeedbackEmail generates an HTML-formatted email body for user feedback
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate input parameters
	if fromAddr == "" {
		return "", fmt.Errorf("fromAddr cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("toAddr cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("userName cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedbackContent cannot be empty")
	}

	// Escape HTML special characters to prevent injection
	userName = escapeHTML(userName)
	subject = escapeHTML(subject)
	feedbackContent = escapeHTML(feedbackContent)

	// Get current timestamp
	timestamp := time.Now().Format("2006-01-02 15:04:05 MST")

	// Build HTML email content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
            border-radius: 5px 5px 0 0;
        }
        .content {
            background-color: #f9f9f9;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
        }
        .value {
            margin-top: 5px;
            padding: 10px;
            background-color: white;
            border-left: 3px solid #4CAF50;
        }
        .feedback-content {
            white-space: pre-wrap;
            word-wrap: break-word;
        }
        .footer {
            margin-top: 20px;
            padding-top: 10px;
            border-top: 1px solid #ddd;
            font-size: 12px;
            color: #777;
        }
    </style>
</head>
<body>
    <div class="header">
        <h2>New User Feedback Received</h2>
    </div>
    <div class="content">
        <div class="field">
            <div class="label">Submitted By:</div>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <div class="label">Feedback Subject:</div>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <div class="label">Feedback Content:</div>
            <div class="value feedback-content">%s</div>
        </div>
        <div class="field">
            <div class="label">Submitted At:</div>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <div class="label">User Email:</div>
            <div class="value">%s</div>
        </div>
    </div>
    <div class="footer">
        <p>This is an automated message from the feedback system. Please respond to the user at their email address.</p>
    </div>
</body>
</html>`, userName, subject, feedbackContent, timestamp, fromAddr)

	// Build complete email message with headers
	var emailBuilder strings.Builder
	emailBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	emailBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	emailBuilder.WriteString(fmt.Sprintf("Subject: User Feedback: %s\r\n", subject))
	emailBuilder.WriteString("MIME-Version: 1.0\r\n")
	emailBuilder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	emailBuilder.WriteString("\r\n")
	emailBuilder.WriteString(htmlBody)

	return emailBuilder.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS
func escapeHTML(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

func main() {
	// Example usage
	fromAddr := "user@example.com"
	toAddr := "support@company.com"
	userName := "John Doe"
	subject := "Issue with login functionality"
	feedbackContent := `I've been experiencing issues logging into my account.
When I enter my credentials, the page just refreshes without any error message.
This has been happening for the past 2 days.

Please help me resolve this issue.

Thank you!`

	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Body:")
	fmt.Println("=" + strings.Repeat("=", 70))
	fmt.Println(emailBody)
	fmt.Println("=" + strings.Repeat("=", 70))

	// Example with validation error
	fmt.Println("\n\nTesting validation:")
	_, err = BuildFeedbackEmail("", toAddr, userName, subject, feedbackContent)
	if err != nil {
		fmt.Printf("Expected error: %v\n", err)
	}
}

