	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeEmailHeader removes or replaces characters that could be used for header injection
func sanitizeEmailHeader(header string) string {
	// Remove newlines and carriage returns to prevent header injection
	header = strings.ReplaceAll(header, "\r", "")
	header = strings.ReplaceAll(header, "\n", "")
	// Remove null bytes
	header = strings.ReplaceAll(header, "\x00", "")
	return header
}

